ALTER TABLE `demandTypeOptions` ADD CONSTRAINT `demandTypeOptions_demandTypeId_demandTypes_id_fk` FOREIGN KEY (`demandTypeId`) REFERENCES `demandTypes`(`id`) ON DELETE no action ON UPDATE no action;
